const body = $json.body ?? $json;
const type = (body.type ?? '').toString().toLowerCase();

if (type !== 'aid_request') {
  return [{
    json: {
      status: 'rejected',
      reason: 'unsupported_type',
      expectedType: 'aid_request',
      receivedType: type || 'unknown',
      session: 'pedago',
      receivedAt: new Date().toISOString()
    }
  }];
}

const requester = body.requester ?? {};
const candidates = Array.isArray(body.candidates) ? body.candidates : [];
const seed = (body.seed ?? requester.selectedSeed ?? '').toString();
const resourceId = (body.resourceId ?? '').toString();

if (!seed || !resourceId) {
  return [{
    json: {
      status: 'rejected',
      reason: 'missing_seed_or_resource',
      session: 'pedago',
      eventType: 'aid_request',
      receivedAt: new Date().toISOString()
    }
  }];
}

const reqCompleted = Array.isArray(requester.completedNodes) ? requester.completedNodes.length : 0;
const reqLevel = Number(requester.level ?? 0);
const reqXp = Number(requester.xp ?? 0);
const reqId = requester.userId ?? null;

const recommendations = candidates
  .filter((candidate) => candidate && candidate.userId && candidate.userId !== reqId)
  .map((candidate) => {
    const cProfile = candidate.profileData ?? {};
    const cSeedEq = cProfile.seedEquipment?.[seed] ?? {};
    const resourceQty = Number(cSeedEq[resourceId] ?? 0);

    const cCompleted = Array.isArray(candidate.completedNodes) ? candidate.completedNodes.length : 0;
    const cLevel = Number(candidate.level ?? 0);
    const cXp = Number(candidate.xp ?? 0);

    const levelGap = cLevel - reqLevel;
    const completedGap = cCompleted - reqCompleted;
    const xpGap = cXp - reqXp;

    const hasResource = resourceQty > 0;
    const progressionEligible = cLevel >= reqLevel && cCompleted >= reqCompleted;
    const progressionTooFar = completedGap > 8;

    const score = (hasResource ? 100 : 0) + Math.max(0, 15 - Math.abs(levelGap) * 3) + Math.max(0, 20 - Math.abs(completedGap) * 2) + Math.max(0, 10 - Math.floor(Math.abs(xpGap) / 300));

    return {
      userId: candidate.userId,
      name: candidate.name ?? 'unknown',
      resourceQty,
      level: cLevel,
      completedCount: cCompleted,
      score,
      guard: {
        hasResource,
        progressionEligible,
        progressionTooFar
      }
    };
  })
  .filter((candidate) => candidate.guard.hasResource && candidate.guard.progressionEligible && !candidate.guard.progressionTooFar)
  .sort((a, b) => b.score - a.score)
  .slice(0, 5);

const safeToRecommend = recommendations.length > 0;

return [{
  json: {
    status: 'accepted',
    session: 'pedago',
    eventType: 'aid_request',
    nextAction: safeToRecommend ? 'peer_aid_suggestion' : 'coach_fallback',
    safeToRecommend,
    requester: {
      userId: reqId,
      seed,
      resourceId,
      level: reqLevel,
      completedCount: reqCompleted
    },
    recommendations,
    guard: {
      requiredState: ['level', 'xp', 'completedNodes', 'selectedSeed', 'profileData.seedEquipment'],
      sourceOfTruth: 'student_progress_snapshot + user_profile_data',
      version: 'v1'
    },
    coachReply: safeToRecommend
      ? 'Des pairs compatibles ont ete identifies selon le materiel disponible et l avancement.'
      : 'Aucun pair strictement compatible. Basculer sur accompagnement coach ou entraide asynchrone.',
    receivedAt: new Date().toISOString()
  }
}];
